class Solution(object):
    def average(self, salary):
        """
        :type salary: List[int]
        :rtype: float
        """
        total_sum = sum(salary)
        min_salary = min(salary)
        max_salary = max(salary)
        return (total_sum - min_salary - max_salary) / (len(salary) - 2)
